#!/usr/bin/env bash
set -euo pipefail

# Freddy Fix It — apply-legal-marketing.sh
# Legal + marketing accuracy pass for live payments:
#   - UserAgreement.tsx: add 6.7 Fees clause (3% client fee + 7% commission), bump effective dates
#   - Home.tsx: payment FAQ now present-tense (payments are LIVE, money held until confirm)
#   - CLAUDE.md: mark Stripe + legal pages as BUILT & LIVE

# --- locate the repo ---
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]:-$0}")" && pwd)"
REPO=""
for d in "$SCRIPT_DIR" ~/Desktop/freddy-fixit ~/freddy-fixit ~/Desktop/Website/freddy-fixit; do
  if [ -d "$d/.git" ]; then REPO="$d"; break; fi
done
if [ -z "$REPO" ]; then echo "❌ Could not find the freddy-fixit git repo." >&2; exit 1; fi
cd "$REPO"
echo "📂 Repo: $REPO"


echo "  → CLAUDE.md"
